/**
 * The operator being used to compare a given number value with the threshold number value.
 * @public
 */
export type ThresholdNumbersComparator = 'greater-than' | 'less-than' | 'greater-than-or-equal-to' | 'less-than-or-equal-to' | 'equal-to' | 'not-equal-to';
/**
 * The operator being used to compare a given string value with the threshold string value.
 * @public
 */
export type ThresholdStringsComparator = 'equal-to' | 'not-equal-to';
/**
 * Can be any valid CSS color value.
 * @public
 */
export type ThresholdColor = string;
/**
 * @public
 */
export type ThresholdPropsWithBackgroundColorOptional = {
    /** The text color used for highlighting matching values. */
    color: ThresholdColor;
    backgroundColor?: ThresholdColor;
};
/**
 * @public
 */
export type ThresholdColors = {
    thresholdColor?: ThresholdColor;
    thresholdBackgroundColor?: ThresholdColor;
};
/**
 * @public
 */
export type ThresholdPropsWithColorOptional = {
    color?: ThresholdColor;
    /** The background color used for highlighting matching values. */
    backgroundColor: ThresholdColor;
};
/**
 * Threshold configuration for number values.
 * @public
 */
export type ThresholdForNumbers = {
    comparator: ThresholdNumbersComparator;
    value: number;
};
/**
 * Threshold configuration for string values.
 * @public
 */
export type ThresholdForStrings = {
    /** The operator being used to compare the object value with the threshold value. */
    comparator: ThresholdStringsComparator;
    /** The threshold value to compare the object value to. */
    value: string;
};
/**
 * Threshold configuration defining a certain condition to match a given value.
 * @public
 */
export type Threshold = (ThresholdForNumbers | ThresholdForStrings) & (ThresholdPropsWithBackgroundColorOptional | ThresholdPropsWithColorOptional);
/**
 * Properties common to all sorts of configurations that support thresholds.
 * @public
 */
export type ThresholdOptions<T extends Threshold = Threshold> = {
    /**
     * The thresholds, applied in the specified order.
     * If more than one threshold matches a value,
     * the threshold specified last in the list will
     * have precedence.
     */
    thresholds?: T[];
};
/**
 * Threshold configuration that can be applied to highlight something matching the id.
 * @public
 */
export type ThresholdRule = {
    /** id on which to apply threshold. */
    id: string;
} & (Omit<ThresholdForNumbers, 'color'> | Omit<ThresholdForStrings, 'color'>);
/**
 * Threshold configuration to highlight something matching the id.
 * @public
 */
export type SingleThreshold = {
    rules?: never;
    id: string;
} & Threshold & Pick<ThresholdRule, 'id'>;
/**
 * @public
 */
export type CombinedThresholds = {
    rules: ThresholdRule[];
} & (ThresholdPropsWithBackgroundColorOptional | ThresholdPropsWithColorOptional);
/**
 * Extended threshold type, accepts multiple rules and id properties used
 * for configuring thresholds.
 * @public
 */
export type ThresholdExtended = SingleThreshold | CombinedThresholds;
